{
  {{%VAR}} = 0;
  if (!window.rosBlockly) window.rosBlockly = {};
  if (!window.rosBlockly._usNextId) window.rosBlockly._usNextId = 0;
  var _usId = window.rosBlockly._usNextId++;
  var configTopic = new ROSLIB.Topic({ ros: ros, name: '/esp32/ultrasonic_config', messageType: 'std_msgs/msg/Int32' });
  configTopic.publish(new ROSLIB.Message({ data: ((_usId << 16) | ({{TRIG_PIN}} << 8) | {{ECHO_PIN}}) }));
  log('Ultrasonic #' + _usId + ': trig=G' + {{TRIG_PIN}} + ', echo=G' + {{ECHO_PIN}});
  if (!window.rosBlockly._usSubs) window.rosBlockly._usSubs = {};
  if (window.rosBlockly._usSubs[_usId]) { window.rosBlockly._usSubs[_usId].unsubscribe(); }
  var _usSub = new ROSLIB.Topic({ ros: ros, name: '/esp32/ultrasonic', messageType: 'std_msgs/msg/Int32' });
  window.rosBlockly._usSubs[_usId] = _usSub;
  _usSub.subscribe(function(msg) { var id = (msg.data >> 16) & 0xFF; var d10 = msg.data & 0xFFFF; if (id === _usId && d10 !== 0xFFFF) { {{%VAR}} = d10 / 10.0; } });
  await wait(0.5);
}

{
  if (!window.rosBlockly) window.rosBlockly = {};
  if (!window.rosBlockly._rgbNextId) window.rosBlockly._rgbNextId = 0;
  var _rgbId = window.rosBlockly._rgbNextId++;
  var configTopic = new ROSLIB.Topic({ ros: ros, name: '/esp32/rgb_led_config', messageType: 'std_msgs/msg/Int32' });
  configTopic.publish(new ROSLIB.Message({ data: ((_rgbId << 24) | ({{R_PIN}} << 16) | ({{G_PIN}} << 8) | {{B_PIN}}) }));
  {{%VAR}} = { id: _rgbId, r_pin: {{R_PIN}}, g_pin: {{G_PIN}}, b_pin: {{B_PIN}} };
  log('RGB LED #' + _rgbId + ': R=G' + {{R_PIN}} + ', G=G' + {{G_PIN}} + ', B=G' + {{B_PIN}});
  await wait(0.1);
}

{
  var _r = Math.max(0, Math.min(255, Math.round({{RED}})));
  var _g = Math.max(0, Math.min(255, Math.round({{GREEN}})));
  var _b = Math.max(0, Math.min(255, Math.round({{BLUE}})));
  var _id = {{%VAR}}.id || 0;
  var rgbTopic = new ROSLIB.Topic({ ros: ros, name: '/esp32/rgb_led_set', messageType: 'std_msgs/msg/Int32' });
  rgbTopic.publish(new ROSLIB.Message({ data: ((_id << 24) | (_r << 16) | (_g << 8) | _b) }));
  log('RGB LED #' + _id + ' → R:' + _r + ' G:' + _g + ' B:' + _b);
}

{
  var _colors = { RED:[255,0,0], GREEN:[0,255,0], BLUE:[0,0,255], YELLOW:[255,255,0], CYAN:[0,255,255], MAGENTA:[255,0,255], WHITE:[255,255,255], OFF:[0,0,0] };
  var _c = _colors['{{$COLOR}}'];
  var _id = {{%VAR}}.id || 0;
  var rgbTopic = new ROSLIB.Topic({ ros: ros, name: '/esp32/rgb_led_set', messageType: 'std_msgs/msg/Int32' });
  rgbTopic.publish(new ROSLIB.Message({ data: ((_id << 24) | (_c[0] << 16) | (_c[1] << 8) | _c[2]) }));
  log('RGB LED #' + _id + ' → ' + '{{$COLOR}}');
}

{
